*/ namespace Module\Banner\Admin\Controller; use Illuminate\Routing\Controller; use ModStart\Admin\Concern\HasAdminQuickCRUD; use ModStart\Admin\Layout\AdminCRUDBuilder; use ModStart\Form\Form; use ModStart\Grid\GridFilter; use ModStart\Support\Concern\HasFields; use Module\Banner\Type\BannerPosition; use Module\Banner\Type\BannerPositionRemark; use Module\Banner\Type\BannerType; use Module\Banner\Util\BannerUtil; class BannerController extends Controller { use HasAdminQuickCRUD; protected function crud(AdminCRUDBuilder $UXxZR) { $UXxZR->init('banner')->field(function ($UXxZR) { $UXxZR->id('id', 'ID'); $UXxZR->select('position', '位置')->optionType(BannerPositionRemark::class); $UXxZR->image('image', '图片'); $UXxZR->radio('type', '样式类型')->optionType(BannerType::class)->when(BannerType::IMAGE_TITLE_SLOGAN_LINK, function ($S_PAU) { $S_PAU->text('title', '标题'); $S_PAU->textarea('slogan', '内容描述'); $S_PAU->text('linkText', '链接文字'); $S_PAU->switch('colorReverse', '颜色反转'); })->when(BannerType::VIDEO, function ($S_PAU) { $S_PAU->video('video', '视频'); })->required(); $UXxZR->color('backgroundColor', '背景色'); $UXxZR->link('link', '链接'); $UXxZR->display('created_at', L('Created At'))->listable(false); $UXxZR->display('updated_at', L('Updated At'))->listable(false); })->gridFilter(function (GridFilter $UGzyw) { $UGzyw->eq('position', '位置')->select(BannerPosition::class); })->hookChanged(function (Form $GtTXi) { BannerUtil::clearCache(); })->canBatchDelete(true)->enablePagination(false)->defaultOrder(array('sort', 'asc'))->canSort(true)->title('轮播图片'); } }